import React, { useState, useEffect } from 'react';

const Navbar = () => {
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 60);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const navLinks = ['Home', 'About', 'Rooms', 'Gallery', 'Contact'];

  const handleNavClick = (e, link) => {
    e.preventDefault();
    const id = link.toLowerCase();
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: 'smooth' });
    setMenuOpen(false);
  };

  return (
    <>
      {/* CSS inside same file */}
      <style>{`
        .navbar {
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          z-index: 1000;
          padding: 20px 0;
          transition: all 0.4s ease;
          background: transparent;
        }

        .navbar--scrolled {
          background: var(--deep-teal);
          padding: 14px 0;
          box-shadow: 0 4px 30px rgba(0,0,0,0.25);
        }

        .navbar__inner {
          display: flex;
          align-items: center;
          gap: 32px;
        }

        .navbar__logo {
          display: flex;
          align-items: center;
          gap: 12px;
          text-decoration: none;
          flex-shrink: 0;
        }

        .logo-icon {
          font-size: 1.4rem;
          color: var(--gold);
        }

        .logo-name {
          font-family: 'Cormorant Garamond', serif;
          font-size: 1.3rem;
          color: white;
        }

        .logo-tagline {
          font-size: 0.6rem;
          color: var(--gold);
          letter-spacing: 0.25em;
        }

        .navbar__links {
          display: flex;
          gap: 32px;
          margin-left: auto;
        }

        .navbar__link {
          font-size: 0.8rem;
          color: rgba(255,255,255,0.85);
          text-decoration: none;
          position: relative;
        }

        .navbar__link:hover {
          color: var(--gold);
        }

        .navbar__cta {
          padding: 10px 24px;
          background: var(--gold);
          color: white;
          text-decoration: none;
        }

        .navbar__hamburger {
          display: none;
          flex-direction: column;
          gap: 5px;
          background: none;
          border: none;
          cursor: pointer;
          margin-left: auto;
        }

        .navbar__hamburger span {
          width: 24px;
          height: 2px;
          background: white;
        }

        .mobile-menu {
          display: none;
          flex-direction: column;
          background: var(--deep-teal);
          max-height: 0;
          overflow: hidden;
        }

        .mobile-menu--open {
          max-height: 400px;
          padding: 20px;
        }

        .mobile-menu__link {
          color: white;
          padding: 10px 0;
          text-decoration: none;
        }

        .mobile-menu__cta {
          background: var(--gold);
          color: white;
          padding: 12px;
          text-align: center;
        }

        @media (max-width: 900px) {
          .navbar__links,
          .navbar__cta {
            display: none;
          }

          .navbar__hamburger {
            display: flex;
          }

          .mobile-menu {
            display: flex;
          }
        }
      `}</style>

      {/* JSX unchanged */}
      <header className={`navbar ${scrolled ? 'navbar--scrolled' : ''}`}>
        <div className="navbar__inner container">

          <a href="#home" className="navbar__logo" onClick={(e) => handleNavClick(e, 'home')}>
            <span className="logo-icon">✦</span>
            <div>
              <span className="logo-name">Sunset Resort</span>
              <span className="logo-tagline">Luxury Awaits</span>
            </div>
          </a>

          <nav className="navbar__links">
            {navLinks.map((link) => (
              <a
                key={link}
                href={`#${link.toLowerCase()}`}
                className="navbar__link"
                onClick={(e) => handleNavClick(e, link)}
              >
                {link}
              </a>
            ))}
          </nav>

          <a
            href="#contact"
            className="navbar__cta"
            onClick={(e) => handleNavClick(e, 'contact')}
          >
            Book Now
          </a>

          <button
            className={`navbar__hamburger ${menuOpen ? 'open' : ''}`}
            onClick={() => setMenuOpen(!menuOpen)}
          >
            <span /><span /><span />
          </button>
        </div>

        <div className={`mobile-menu ${menuOpen ? 'mobile-menu--open' : ''}`}>
          {navLinks.map((link) => (
            <a
              key={link}
              href={`#${link.toLowerCase()}`}
              className="mobile-menu__link"
              onClick={(e) => handleNavClick(e, link)}
            >
              {link}
            </a>
          ))}
          <a
            href="#contact"
            className="mobile-menu__cta"
            onClick={(e) => handleNavClick(e, 'contact')}
          >
            Book Now
          </a>
        </div>
      </header>
    </>
  );
};

export default Navbar;
